var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. AS003M0008: <color=#ffd34c>유진</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>……\\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>……\\nCCN No. AS003M0008：<color=#ffd34c>シロコ</color>","ENG":"[[","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. AS003M0008: <color=#ffd34c>劉珍</color>","THA":"กระบวนการตรวจสอบประวัติเพื่อความปลอดภัย AEGIS 8 PBLIT: <color=#ffd34c>เริ่มการทำงาน</color>     \\nADC แฟกเตอร์: <color=#ffd34c>ยืนยันในระดับอัลฟ่า</color>     \\nCCN หมายเลข AS003M0008: <color=#ffd34c>ยูจิน</color>","VTN":"TRÌNH TỰ AN NINH AEGIS 8 PBLIT: <color=#ffd34c>ĐÃ KÍCH HOẠT</color>     \\nTHÔNG SỐ ADC: <color=#ffd34c>XÁC NHẬN ALPHA </color>     \\nCCN Số AS003M0008: <color=#ffd34c>Eujin</color>","SCN":"AEGIS 8 PBLIT安全序列: <color=#ffd34c>激活</color>\\nADC 因素: <color=#ffd34c>阿尔法确认</color>     \\nCCN No. AS003M0008: <color=#ffd34c>刘珍</color>","DEU":"AEGIS 8 PBLIT-SICHERHEITSSEQUENZ: <color=#ffd34c>AKTIVIERT</color>     \\nADC-FAKTOR: <color=#ffd34c>ALPHA BESTÄTIGT</color>     \\nCCN-Nr. AS003M0008: <color=#ffd34c>Eujin</color>","FRA":"AEGIS 8 PROTOCOLE DE SÉCURITÉ PBLIT\xA0: <color=#ffd34c>ACTIVÉ</color>     \\nFACTEUR CAD\xA0: <color=#ffd34c>ALPHA CONFIRMÉ</color>     \\nCCN No. AS003M0008\xA0: <color=#ffd34c>Eujin</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"이제 채용 심사도 마지막 절차만 남았네요.","JPN":"もう採用審査も最後の手続きを残すのみですね。","ENG":"There is only one last step for the recruitment process.","TWN":"招聘審查也只剩下最後一個程序了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"모두들 고생하셨습니다.","JPN":"皆さんにはご迷惑をおかけしております。","ENG":"Good work, everyone.","TWN":"大家都辛苦了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아뇨. 고생은 관리부장님께서 더 많이 하셨죠.","JPN":"そんなことありません。管理部長がいてくださって色々と助かりました。","ENG":"No, you're the one who did all the work.","TWN":"不，管理部長您比較辛苦吧。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"저희야 시키는 대로 한 것밖에 없는 걸요.","JPN":"私たちは指示に従うだけでよかったんですから。","ENG":"All we did was follow your directions.","TWN":"我們只是照您吩咐的去做而已"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"아자!! 드디어 끝이다!","JPN":"よっしゃぁ！！これでやっとおしまいだな！","ENG":"Yeah! It's finally over!","TWN":"好耶！！終於要結束了！"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"하품 참느라 죽는 줄 알았네!","JPN":"もうあくび我慢するのが大変でさ～！","ENG":"It was so hard trying to hold back my yawns!","TWN":"我真的睏死了！"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"방금 얘기 못 들었어? 아직 하나 더 남았다잖아.","JPN":"さっきの話聞いてなかったの？まだ何か残ってるみたいよ。","ENG":"Didn't you hear? There still one step left.","TWN":"妳剛才沒聽到嗎？不是還剩一個程序沒跑嗎？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"막상 해 보니까 별거 없던데, 뭐! 얼른 해치워 버리자고!","JPN":"どうせこれまで通り大したことないんだろ？さっさと片付けちまおうぜ！","ENG":"It's not as difficult as I thought. Let's get this over with!","TWN":"又沒什麼大不了的！怕什麼？三兩下把它解決掉吧！"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"아니면 혹시 떨어질까 봐 긴장했냐?","JPN":"それとも何か？審査に落ちるんじゃないかってビビってんのか？","ENG":"Or are you nervous because you might fail?","TWN":"還是妳怕會落選，所以在緊張吼？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"간은 콩알만 해 가지고. 그러니까 뒤에서 딱총만 쏘고 있지.","JPN":"肝っ玉の小っさい奴だなぁ。だから後ろでパチンコばっか撃ってんだろ？","ENG":"You're such a wimp. That's why you always stay in the back with that toy gun of yours.","TWN":"真是膽小如豆。怪不得妳只敢龜在後面玩BB槍而已。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"리, 린. 여기서 또 총을 쏘면 채용이 취소될지도 몰라.","JPN":"リ、リン。ここでまた発砲したら、採用が取り消しになっちゃうかも……","ENG":"L-Lin. If you start shooting here again, they might cancel recruitment.","TWN":"琳、琳。如果妳又在這裡開槍，錄用資格可能會被取消呀。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"하하, 유진 양은 요즘 젊은이들답지 않게 적극적이네요.","JPN":"あはは♪シロコさんはとっても積極的な方ですね。今時の若い方には珍しいですよ。","ENG":"Hah hah, Eujin, you're quite passionate, unlike other youngsters these days.","TWN":"哈哈，劉珍小姐不像現在的年輕人那樣，很積極呢。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아주 좋습니다. 저희 회사 일에 적성이 잘 맞겠어요.","JPN":"弊社の仕事に向いていると思います。","ENG":"Very good. You'll fit right into our company.","TWN":"非常好。很適合在我們公司工作。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"야, 멸치. 방금 들었지? 나중에 내가 네 상사 됐다고 질질 짜지 마라?","JPN":"おい、イワシ。今の聞いただろ？あとで俺がお前の上司になっても、メソメソ泣いたりするなよな。","ENG":"Hey, Weak Sauce. Hear that? Don't cry when I become your superior.","TWN":"喂，小魚乾，妳剛才聽到了吧？要是以後我成為了妳的上司，妳可別在那邊哭喔？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"시끄러워. 돼지야.","JPN":"ブーちゃんはいい加減黙ってて。","ENG":"Shut it, Pig.","TWN":"吵死了，蠢豬。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};